$apiKey = "YOUR_BREVO_API_KEY"; $headers = @{ "api-key" = $apiKey; "Accept" = "application/json" }; try { $senders = Invoke-RestMethod -Uri "https://api.brevo.com/v3/senders" -Method Get -Headers $headers; $domains = Invoke-RestMethod -Uri "https://api.brevo.com/v3/senders/domains" -Method Get -Headers $headers; @{ senders = $senders; domains = $domains } | ConvertTo-Json -Depth 5 } catch { $_ | ConvertTo-Json }
